import{c as t,Q as a,j as o,m as i}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"OpenClaw + Telegram — overview","description":"Phone-first MuHaven via OpenClaw skill and the MuHaven Telegram bot.","frontmatter":{"title":"OpenClaw + Telegram — overview","description":"Phone-first MuHaven via OpenClaw skill and the MuHaven Telegram bot."},"headers":[],"relativePath":"openclaw/overview.md","filePath":"openclaw/overview.md","lastUpdated":1780245214000}'),r={name:"openclaw/overview.md"};function n(l,e,s,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="openclaw-telegram" tabindex="-1">OpenClaw + Telegram <a class="header-anchor" href="#openclaw-telegram" aria-label="Permalink to &quot;OpenClaw + Telegram&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">🚧 In development — not in the Testing Guide</p><p>The OpenClaw Telegram bot, device-link (<code>/link</code>), and intent-confirm (<code>/agent/confirm</code>) surfaces aren&#39;t ready for general testing yet, so they&#39;re excluded from the <a href="/guide/">Testing Guide</a>. These pages describe the intended design. The same agentic capabilities are testable today via <a href="/havenbot/overview">HavenBot</a> and the <a href="/mcp/overview">MCP server</a>.</p></div><p>The OpenClaw surface is MuHaven&#39;s <strong>phone-first</strong> interface. It bundles three things:</p><ol><li><strong><code>muhaven-rwa-skill</code></strong> — an <a href="https://openclaw.dev" target="_blank" rel="noreferrer">OpenClaw</a> skill (in development; not yet published). Once published, you install it into your OpenClaw runtime; the skill bundles <code>@muhaven/mcp</code> with an investor-only subset (11 of 25 tools).</li><li><strong><code>@muhaven_bot</code></strong> — the official MuHaven Telegram bot (live). Conversational interface for the same 11 tools.</li><li><strong>Telegram Mini App</strong> — the in-Telegram web view that handles mid-tier confirmations (the $200-$5K window); part of the in-development OpenClaw mid-tier flow.</li></ol><p>All three share the same MuHaven wallet and the same audit log as HavenBot, MCP, and the hosted checkout.</p><h2 id="what-s-available" tabindex="-1">What&#39;s available <a class="header-anchor" href="#what-s-available" aria-label="Permalink to &quot;What&#39;s available&quot;">​</a></h2><p>The <strong>Telegram bot is live</strong> — one of MuHaven&#39;s three live surfaces (HavenBot, <code>@muhaven/mcp</code>, Telegram). The <strong>OpenClaw skill</strong> and the <strong>Telegram Mini App</strong> are still in development.</p><table tabindex="0"><thead><tr><th>Component</th><th>Status</th></tr></thead><tbody><tr><td><code>muhaven-rwa-skill</code> (OpenClaw skill)</td><td>In development — not yet published</td></tr><tr><td><code>@muhaven_bot</code> Telegram bot</td><td>Live on Arbitrum Sepolia (testnet)</td></tr><tr><td>Telegram Mini App</td><td>In development (mid-tier confirmation UI)</td></tr><tr><td>Three-tier confirmation classifier</td><td>Inline ≤$200 / Mini-App OTP $200–$5K / passkey deeplink &gt;$5K</td></tr><tr><td>Sigstore + GitHub OIDC publish</td><td>Trusted publisher configured; tag-push will trigger a signed release</td></tr></tbody></table><h2 id="the-11-tool-subset-and-what-s-deliberately-excluded" tabindex="-1">The 11-tool subset (and what&#39;s deliberately excluded) <a class="header-anchor" href="#the-11-tool-subset-and-what-s-deliberately-excluded" aria-label="Permalink to &quot;The 11-tool subset (and what&#39;s deliberately excluded)&quot;">​</a></h2><p>The OpenClaw skill includes:</p><ul><li><strong>All 5 read tools</strong> — <code>portfolio</code>, <code>yields</code>, <code>distribution</code>, <code>tokens</code>, <code>audit</code>.</li><li><strong>The 2 protection / KYC read tools</strong> — <code>protection_coverage</code>, <code>kyc_attestation</code>.</li><li><strong>2 of 4 position tools</strong> — <code>buy</code>, <code>claim</code>.</li><li><strong>2 of 4 policy tools</strong> — <code>pause</code>, <code>session_key_status</code>.</li></ul><p>Deliberately excluded:</p><ul><li><code>position.sell</code> and <code>position.rebalance</code> — multi-leg ceremonies don&#39;t fit a three-tier Telegram confirmation.</li><li><code>policy.set_tier</code> and <code>policy.audit_export</code> — tier transitions need the dashboard ceremony; audit export needs a download surface.</li><li>All 5 <code>issuer.*</code> tools — Telegram is investor-only.</li><li>Both <code>governance.*</code> tools — encrypted vote ceremony needs the cofhe SDK in a browser; Telegram can&#39;t drive it.</li></ul><p>If you need the excluded tools, use <a href="/havenbot/overview">HavenBot</a> or <a href="/mcp/overview"><code>@muhaven/mcp</code></a>.</p><h2 id="the-three-confirmation-tiers" tabindex="-1">The three confirmation tiers <a class="header-anchor" href="#the-three-confirmation-tiers" aria-label="Permalink to &quot;The three confirmation tiers&quot;">​</a></h2><p>The classifier is <strong>pure</strong> — it takes the USD amount and returns one of three tiers:</p><table tabindex="0"><thead><tr><th>USD amount (mhUSDC)</th><th>Tier</th><th>Surface</th></tr></thead><tbody><tr><td>≤ $200</td><td><strong>Inline</strong></td><td>Telegram inline keyboard button → tap → done</td></tr><tr><td>$200 – $5,000</td><td><strong>Mini-App OTP</strong></td><td>Telegram Mini App opens → 6-digit OTP delivered out-of-band → enter → confirm</td></tr><tr><td>&gt; $5,000</td><td><strong>Passkey deeplink</strong></td><td>Telegram deep-link → opens dashboard <code>/agent/confirm</code> → passkey signature</td></tr></tbody></table><p>The classifier is <strong>locked at the type level</strong> — investors cannot raise the boundaries above the hardcoded ceilings (Reg BI Care Obligation framing).</p><p>Each tier emits a different audit-log <code>source</code> so you can tell which surface drove a given commit:</p><ul><li><code>inline</code> → <code>telegram_inline</code></li><li><code>mini-app</code> → <code>mini_app</code></li><li><code>deeplink</code> → <code>dashboard_passkey</code></li></ul><p>See <a href="/openclaw/confirmation-tiers">Three confirmation tiers</a> for the full flow per tier.</p><h2 id="how-openclaw-fits-in" tabindex="-1">How OpenClaw fits in <a class="header-anchor" href="#how-openclaw-fits-in" aria-label="Permalink to &quot;How OpenClaw fits in&quot;">​</a></h2><p><a href="https://openclaw.dev" target="_blank" rel="noreferrer">OpenClaw</a> is an open standard for agent skills — bundled MCP servers + a manifest that declares network egress, secret storage, and tool subset. The MuHaven skill (<code>muhaven-rwa-skill</code>) is in development; once published it will live on <a href="https://clawhub.com" target="_blank" rel="noreferrer">ClawHub</a> (the central skill registry).</p><p>When you install the skill, the OpenClaw runtime:</p><ol><li>Verifies the skill&#39;s Sigstore signature against the GitHub OIDC issuer.</li><li>Validates the manifest&#39;s <code>network.egress_allowlist</code> (only <code>api.muhaven.app</code> + <code>muhaven.app</code>).</li><li>Starts the bundled <code>@muhaven/mcp</code> server with the 11-tool subset filter.</li><li>Wires the broker daemon for signing.</li></ol><p>The runtime enforces the manifest&#39;s permissions — even if a malicious LLM tried to call <code>position.sell</code>, the skill subset filter would refuse to register it.</p><h2 id="how-the-telegram-bot-fits-in" tabindex="-1">How the Telegram bot fits in <a class="header-anchor" href="#how-the-telegram-bot-fits-in" aria-label="Permalink to &quot;How the Telegram bot fits in&quot;">​</a></h2><p>The Telegram bot is a <strong>separate runtime</strong> from the OpenClaw skill — they don&#39;t share processes. The bot is a small Express service that:</p><ol><li>Listens on an outbound webhook for Telegram updates.</li><li>Validates Telegram&#39;s <code>initData</code> HMAC against the bot token.</li><li>For each command, calls the same backend HTTP routes the MCP / HavenBot surfaces use.</li><li>Renders the response as Telegram messages, inline buttons, or Mini-App launches.</li></ol><p>The bot <strong>does not run an LLM</strong> — it&#39;s a deterministic command interpreter. The bot edge sees your Telegram chat ID and the inline button you tapped; it never sees an LLM context.</p><h2 id="when-to-use-openclaw-telegram" tabindex="-1">When to use OpenClaw + Telegram <a class="header-anchor" href="#when-to-use-openclaw-telegram" aria-label="Permalink to &quot;When to use OpenClaw + Telegram&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Question</th><th>If yes → OpenClaw</th></tr></thead><tbody><tr><td>Do you primarily work from a phone?</td><td>✅</td></tr><tr><td>Do you want one-tap actions for sub-$200 buys?</td><td>✅</td></tr><tr><td>Do you want the dashboard&#39;s passkey ceremony for big trades?</td><td>✅ (the &gt;$5K tier deeplinks to it)</td></tr><tr><td>Do you need issuer tools?</td><td>❌ Use <a href="/havenbot/overview">HavenBot</a> — Telegram is investor-only</td></tr><tr><td>Do you want to bring your own LLM?</td><td>❌ Use <a href="/mcp/overview">MCP</a> — Telegram has no LLM edge</td></tr><tr><td>Do you want multi-leg rebalances?</td><td>❌ Use <a href="/havenbot/overview">HavenBot</a> — rebalance is excluded from the skill subset</td></tr></tbody></table><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><div class="mh-card-grid"><a class="mh-card" href="/openclaw/install-skill"><h3>Install the skill</h3><p>Get muhaven-rwa-skill running in OpenClaw.</p></a><a class="mh-card" href="/openclaw/telegram-bot"><h3>Telegram bot</h3><p>Link your Telegram, send your first command.</p></a><a class="mh-card" href="/openclaw/confirmation-tiers"><h3>Three confirmation tiers</h3><p>How inline / Mini App / passkey deeplink actually work.</p></a><a class="mh-card" href="/openclaw/tools"><h3>Available tools</h3><p>The 11-tool subset, what each does, and how to invoke it.</p></a><a class="mh-card" href="/openclaw/playbook"><h3>Playbook — phone-first scenarios</h3><p>Commuting check-in, claim from bed, train-station tier switch.</p></a></div>',34)])])}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
